def solve(ftp_data, parcel_requests):
    # Parse the FTP data
    flights = parse_ftp_data(ftp_data)

    # Match parcel requests to available flights
    reservations = []
    for request in parcel_requests:
        matching_flight = find_matching_flight(flights, request)
        if matching_flight:
            reservations.append(create_reservation(matching_flight, request))

    return reservations

def parse_ftp_data(ftp_data):
    # Implement parsing logic for EDITFACTS format
    flights = []
    for line in ftp_data.splitlines():
        flight_info = line.split(',')
        flights.append({
            'flight_number': flight_info[0],
            'departure_time': flight_info[1],
            'available_capacity': int(flight_info[2])
        })
    return flights

def find_matching_flight(flights, request):
    for flight in flights:
        if flight['available_capacity'] >= request['weight']:
            return flight
    return None

def create_reservation(flight, request):
    return {
        'flight_number': flight['flight_number'],
        'parcel_id': request['id'],
        'weight': request['weight']
    }
